import React, { useEffect, useRef, useState } from "react";
import "./EeshaWalkComponent.css";

const EeshaWalkComponent = ({ audioCtx, soundType, onStop }) => {
  const [steps, setSteps] = useState(0);
  const [isSensorsStarted, setIsSensorsStarted] = useState(false);
  const [isFrozen, setIsFrozen] = useState(false); // For the .eesha-frozen state in your CSS
  
  const lastStepTime = useRef(0);
  const threshold = 12; 

  useEffect(() => {
    let sensor;
    const startSensors = async () => {
      try {
        if ('LinearAccelerationSensor' in window) {
          sensor = new window.LinearAccelerationSensor({ frequency: 60 });
          sensor.addEventListener("reading", () => {
            const { x, y, z } = sensor;
            const magnitude = Math.sqrt(x * x + y * y + z * z);
            
            if (magnitude > threshold) {
              const now = Date.now();
              if (now - lastStepTime.current > 350) {
                setSteps((prev) => prev + 1);
                lastStepTime.current = now;
                playClick();
              }
            }
          });
          sensor.start();
          setIsSensorsStarted(true);
        }
      } catch (error) {
        console.error("Sensor error:", error);
      }
    };

    const playClick = () => {
      if (!audioCtx) return;
      const oscillator = audioCtx.createOscillator();
      const gainNode = audioCtx.createGain();
      oscillator.connect(gainNode);
      gainNode.connect(audioCtx.destination);
      oscillator.type = soundType === "marimba" ? "sine" : "square";
      oscillator.frequency.setValueAtTime(soundType === "marimba" ? 880 : 440, audioCtx.currentTime);
      gainNode.gain.setValueAtTime(0.1, audioCtx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.1);
      oscillator.start();
      oscillator.stop(audioCtx.currentTime + 0.1);
    };

    startSensors();
    return () => { if (sensor) sensor.stop(); };
  }, [audioCtx, soundType]);

  return (
    <div className={`eesha-walk ${isFrozen ? "eesha-frozen" : ""}`}>
      {/* Status Label */}
      <div className="eesha-status">
        {isSensorsStarted ? "Sensors Live" : "Initializing..."}
      </div>

      {/* BPM/Step Display Area */}
      <div className="eesha-bpm-display">
        <div className="eesha-bpm-number">{steps}</div>
        <div className="eesha-bpm-unit">Total Steps</div>
      </div>

      {/* Stat Row */}
      <div className="eesha-stat-row">
        <div className="eesha-stat">
          <div className="eesha-stat-value">0</div>
          <div className="eesha-stat-label">Min</div>
        </div>
        
        <div className="eesha-stat-divider"></div>
        
        <div className="eesha-stat">
          <div className="eesha-stat-value">0.0</div>
          <div className="eesha-stat-label">KM</div>
        </div>
      </div>

      {/* Stop Button */}
      <button className="eesha-stop-btn" onClick={onStop}>
        End Session
      </button>
    </div>
  );
};

export default EeshaWalkComponent;
